firmware_template.source:
#include "dac_mcp4725.h"
#include <Wire.h>
#include <Adafruit_MCP4725.h>
static Adafruit_MCP4725 dac;
void mcp4725_setup(){Wire.begin();dac.begin(0x60);Serial.println("[dac] OK 12-bit");}
void mcp4725_set_voltage(float v){uint16_t raw=(uint16_t)(v/3.3*4095);dac.setVoltage(raw,false);}
void mcp4725_set_raw(uint16_t v){dac.setVoltage(v,false);}
